import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"44A. Manager Allowance","description":"","frontmatter":{"title":"44A. Manager Allowance","eba":"Medical Specialists 2022-2026","topics":["allowances"]},"headers":[],"relativePath":"ebas/medical-specialists/allowances/44A-manager-allowance.md","filePath":"ebas/medical-specialists/allowances/44A-manager-allowance.md"}'),n={name:"ebas/medical-specialists/allowances/44A-manager-allowance.md"};function i(l,e,s,c,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_44a-manager-allowance" tabindex="-1">44A. Manager Allowance <a class="header-anchor" href="#_44a-manager-allowance" aria-label="Permalink to &quot;44A. Manager Allowance&quot;">​</a></h1><p><strong>44A.1</strong> From the FFPPOA 11 April 2022, a Doctor who maintains an active clinical role within the relevant speciality at the Health Service and is appointed by the Employer to the role of:</p><p><strong>(a)</strong> Deputy Director (or equivalent); or,</p><p><strong>(b)</strong> Director (or equivalent); or,</p><p><strong>(c)</strong> Program Director (or equivalent)</p><p>will be paid a weekly Manager Allowance equivalent to 2.5% of the minimum weekly rate of pay applicable to the Doctor’s classification as provided in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement (pro-rata for Fractional Doctors).</p><p><strong>44A.2</strong> Where a Doctor’s actual contracted rate of pay is:</p><p><strong>(a)</strong> more than the relevant rate set out in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement; and/or</p><p><strong>(b)</strong> the Doctor receives additional paid hours as compensation for their management role, and the total of this amount is more than the relevant rate set out in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement</p><p>the Doctor will be entitled under this Agreement to receive the contracted rate of pay, or the sum calculated in accordance with subclause 44A.1, whichever is the higher.</p>',10)])])}const g=a(n,[["render",i]]);export{m as __pageData,g as default};
